328→/// <summary>
329→/// 개별 비트 상태 뷰모델
330→/// </summary>
331→public class BitViewModel : INotifyPropertyChanged
332→{
333→    public int BitIndex { get; }
334→    public string Address { get; }
335→    public string Unit { get; }
