161→    /// <summary>
162→    /// 주기적으로 PLC MW 영역 읽기 + Heartbeat 쓰기
163→    /// </summary>
164→    private async Task PollLoopAsync(CancellationToken ct)
165→    {
166→        while (!ct.IsCancellationRequested)
167→        {
168→            var sw = System.Diagnostics.Stopwatch.StartNew();
169→            try
170→            {
171→                // ★ Heartbeat 쓰기 — 매 사이클 최우선 (연결 중 무조건)
172→                _heartbeatCount++;
173→                ushort heartbeat = (ushort)(_heartbeatCount | 0x0100); // bit8=PC_READY
174→                await _client.WriteWordsAsync("%MW500", [heartbeat]);
175→
176→                // 입력 읽기: MW100~109 (10 WORD)
177→                var inputs = await _client.ReadWordsAsync("%MW100", 10);
178→                if (inputs != null)
179→                    UpdateWordViewModels(InputWords, inputs);
180→
181→                // 출력 읽기: MW200~209 (10 WORD) — readback
182→                var outputs = await _client.ReadWordsAsync("%MW200", 10);
183→                if (outputs != null)
184→                {
185→                    // 출력 캐시 동기화 (PLC에서 읽은 값 반영)
186→                    Array.Copy(outputs, _outputCache, Math.Min(outputs.Length, 10));
187→                    UpdateWordViewModels(OutputWords, outputs);
188→                }
189→
190→                // 서보 명령 읽기: MW300~301 (2 WORD)
191→                var servoCmds = await _client.ReadWordsAsync("%MW300", 2);
192→
193→                // 서보 파라미터 읽기: MW310~319 (10 WORD)
194→                var servoParams = await _client.ReadWordsAsync("%MW310", 10);
195→
196→                // 서보 상태 읽기: MW400~401 (2 WORD)
197→                var servoStatus = await _client.ReadWordsAsync("%MW400", 2);
198→
199→                // 서보 값 읽기: MW410~415 (6 WORD)
200→                var servoValues = await _client.ReadWordsAsync("%MW410", 6);
201→
202→                // 시스템 읽기: MW500~501 (2 WORD)
203→                var system = await _client.ReadWordsAsync("%MW500", 2);
204→
205→                // MW501 파싱 — PLC 상태 비트 + PLC 하트비트
206→                if (system is { Length: >= 2 })
207→                {
208→                    var mw501 = system[1];
209→                    Application.Current?.Dispatcher.Invoke(() =>
210→                    {
211→                        PlcCommOk = (mw501 & 0x0001) != 0;
212→                        PlcEmoActive = (mw501 & 0x0002) != 0;
213→                        PlcServoErr = (mw501 & 0x0004) != 0;
214→                        PlcWdTimeout = (mw501 & 0x0008) != 0;
215→                        PlcRun = (mw501 & 0x0010) != 0;
216→                        PlcHeartbeat = (byte)(mw501 >> 8);
217→                    });
218→                }
219→
220→                // 서보/시스템 탭 업데이트 + WRITE 캐시 동기화
221→                var servoSysData = new ushort[6];
222→                if (servoCmds != null) { servoSysData[0] = servoCmds[0]; servoSysData[1] = servoCmds[1]; }
223→                if (servoStatus != null) { servoSysData[2] = servoStatus[0]; servoSysData[3] = servoStatus[1]; }
224→                if (system != null) { servoSysData[4] = system[0]; servoSysData[5] = system[1]; }
225→                Array.Copy(servoSysData, _servoSysCache, 6);
226→                UpdateWordViewModels(ServoSystemWords, servoSysData);
227→
228→                // 서보 파라미터/값 (DINT) 업데이트
229→                if (servoParams is { Length: >= 6 })
230→                {
231→                    Application.Current?.Dispatcher.Invoke(() =>
232→                    {
233→                        TargetPos = (int)(servoParams[0] | (servoParams[1] << 16));
234→                        TargetVel = (int)(servoParams[2] | (servoParams[3] << 16));
235→                        JogVel = (int)(servoParams[4] | (servoParams[5] << 16));
236→                    });
237→                }
238→                if (servoValues is { Length: >= 6 })
239→                {
240→                    Application.Current?.Dispatcher.Invoke(() =>
241→                    {
242→                        ActPos = (int)(servoValues[0] | (servoValues[1] << 16));
243→                        ActVel = (int)(servoValues[2] | (servoValues[3] << 16));
244→                        ErrCode = servoValues[4];
245→                        ActPosDeg = servoValues[5];
246→                    });
247→                }
248→
249→                sw.Stop();
250→                Application.Current?.Dispatcher.Invoke(() =>
251→                {
252→                    CycleMs = (int)sw.ElapsedMilliseconds;
253→                    var plcSts = PlcRun ? "RUN" : (PlcWdTimeout ? "WD!" : "---");
254→                    ConnectionStatus = $"연결됨 ({_client.IpAddress}) — {CycleMs}ms | PC:{_heartbeatCount} PLC:{PlcHeartbeat} | {plcSts}";
255→                });
256→            }
257→            catch (Exception ex)
258→            {
259→                Application.Current?.Dispatcher.Invoke(() =>
260→                {
261→                    ConnectionStatus = $"통신 에러: {ex.Message}";
262→                });
263→            }
264→
265→            // Delay 없음 — 통신 사이클(~50ms) 자체가 주기
266→            await Task.Yield();
267→        }
268→    }
