141→    /// <summary>
142→    /// 응답 패킷 파싱 결과
143→    /// </summary>
144→    public record ParseResult(
145→        bool Success,
146→        ushort Command,
147→        ushort DataType,
148→        ushort[]? Words,
149→        string ErrorInfo);
