 11→/// <summary>
 12→/// 서보 제어 패널 뷰모델
 13→/// MW300~301(명령), MW310~313(파라미터), MW400~401(상태), MW410~414(값)
 14→/// JOG: %UW0.9.1 직접 쓰기
 15→/// </summary>
 16→public class ServoControlViewModel : INotifyPropertyChanged, IDisposable
 17→{
 18→    private readonly XgtClient _client = new();
 19→    private CancellationTokenSource? _cts;
 20→
 21→    // === 상태 표시 (READ) ===
 22→    private bool _stsMoving, _stsError, _stsRdy, _stsServoMc;
 23→    private bool _rspHomeDone, _rspMoveDone, _rspHomeErr, _rspMoveErr, _rspResetDone;
 24→    private int _actPos, _actVel;
 25→    private ushort _errCode;
 26→    private ushort _mw400Raw, _mw401Raw;
 27→
 28→    public bool StsMoving { get => _stsMoving; set { _stsMoving = value; N(); } }
 29→    public bool StsError { get => _stsError; set { _stsError = value; N(); } }
 30→    public bool StsRdy { get => _stsRdy; set { _stsRdy = value; N(); } }
 31→    public bool StsServoMc { get => _stsServoMc; set { _stsServoMc = value; N(); } }
 32→    public bool RspHomeDone { get => _rspHomeDone; set { _rspHomeDone = value; N(); } }
 33→    public bool RspMoveDone { get => _rspMoveDone; set { _rspMoveDone = value; N(); } }
 34→    public bool RspHomeErr { get => _rspHomeErr; set { _rspHomeErr = value; N(); } }
 35→    public bool RspMoveErr { get => _rspMoveErr; set { _rspMoveErr = value; N(); } }
 36→    public bool RspResetDone { get => _rspResetDone; set { _rspResetDone = value; N(); } }
 37→    public int ActPos { get => _actPos; set { _actPos = value; N(); N(nameof(ActPosDeg)); } }
 38→    public int ActVel { get => _actVel; set { _actVel = value; N(); } }
 39→    public ushort ErrCode { get => _errCode; set { _errCode = value; N(); } }
 40→    public string ActPosDeg => $"{ActPos / 1000.0:F3}°";
 41→    public string Mw400Hex => $"0x{_mw400Raw:X4}";
 42→    public string Mw401Hex => $"0x{_mw401Raw:X4}";
 43→
 44→    // === U영역 모니터 (%UW0.9.0 ~ %UW0.9.1) ===
 45→    private ushort _uw090Raw, _uw091Raw;
 46→    private bool _uPosEl, _uNegEl, _uDog, _uZPhase, _uOrgDone, _uDstDone, _uModuleRdy;
 47→
 48→    public bool UPosEl { get => _uPosEl; set { _uPosEl = value; N(); } }
 49→    public bool UNegEl { get => _uNegEl; set { _uNegEl = value; N(); } }
 50→    public bool UDog { get => _uDog; set { _uDog = value; N(); } }
 51→    public bool UZPhase { get => _uZPhase; set { _uZPhase = value; N(); } }
 52→    public bool UOrgDone { get => _uOrgDone; set { _uOrgDone = value; N(); } }
 53→    public bool UDstDone { get => _uDstDone; set { _uDstDone = value; N(); } }
 54→    public bool UModuleRdy { get => _uModuleRdy; set { _uModuleRdy = value; N(); } }
 55→    public string Uw090Hex => $"0x{_uw090Raw:X4}";
 56→    public string Uw091Hex => $"0x{_uw091Raw:X4}";
 57→
 58→    // === 파라미터 입력 (WRITE) ===
 59→    private string _targetPosText = "0";
 60→    private string _targetVelText = "10000";
 61→    private bool _isMoveRel;
 62→
 63→    public string TargetPosText { get => _targetPosText; set { _targetPosText = value; N(); } }
 64→    public string TargetVelText { get => _targetVelText; set { _targetVelText = value; N(); } }
 65→    public bool IsMoveRel { get => _isMoveRel; set { _isMoveRel = value; N(); } }
 66→
 67→    // === 연결 상태 ===
 68→    private string _connStatus = "미연결";
 69→    private bool _isConnected;
 70→    private int _cycleMs;
 71→    private string _lastCmd = "";
 72→
 73→    public string ConnStatus { get => _connStatus; set { _connStatus = value; N(); } }
 74→    public bool IsConnected { get => _isConnected; set { _isConnected = value; N(); } }
 75→    public int CycleMs { get => _cycleMs; set { _cycleMs = value; N(); } }
 76→    public string LastCmd { get => _lastCmd; set { _lastCmd = value; N(); } }
 77→
 78→    // === 연결/해제 ===
 79→    public async Task ConnectAsync()
 80→    {
 81→        ConnStatus = "연결 중...";
 82→        if (!await _client.ConnectAsync())
 83→        {
 84→            ConnStatus = "연결 실패";
 85→            return;
 86→        }
 87→        IsConnected = true;
 88→        ConnStatus = "연결됨";
 89→        _cts = new CancellationTokenSource();
 90→        _ = Task.Run(() => PollLoopAsync(_cts.Token));
 91→    }
 92→
 93→    public void Disconnect()
 94→    {
 95→        _cts?.Cancel();
 96→        _client.Disconnect();
 97→        IsConnected = false;
 98→        ConnStatus = "미연결";
 99→    }
100→
101→    // === 서보 명령 (MW300 비트 토글) ===
102→    public async Task CmdHomeAsync()
103→    {
104→        LastCmd = "원점복귀 실행...";
105→        await WriteMw300Bit(0, true);
106→    }
107→
108→    public async Task CmdMoveAsync()
109→    {
110→        if (!int.TryParse(TargetPosText, out var pos) ||
111→            !int.TryParse(TargetVelText, out var vel))
112→        {
113→            LastCmd = "파라미터 입력 오류 (정수 필요)";
114→            return;
115→        }
116→
117→        // MW301.1: 절대/상대
118→        ushort mw301 = (ushort)(IsMoveRel ? 0x0002 : 0x0000);
119→        await _client.WriteWordsAsync("%MW301", [mw301]);
120→
121→        // MW310~313: 위치(DINT) + 속도(DINT)
122→        ushort posL = (ushort)(pos & 0xFFFF);
123→        ushort posH = (ushort)((pos >> 16) & 0xFFFF);
124→        ushort velL = (ushort)(vel & 0xFFFF);
125→        ushort velH = (ushort)((vel >> 16) & 0xFFFF);
126→        await _client.WriteWordsAsync("%MW310", [posL, posH, velL, velH]);
127→
128→        LastCmd = $"이동: pos={pos}, vel={vel}, {(IsMoveRel ? "상대" : "절대")}";
129→        await WriteMw300Bit(1, true);
130→    }
131→
132→    public async Task CmdStopAsync()
133→    {
134→        LastCmd = "즉시정지";
135→        await WriteMw300Bit(4, true);
136→    }
137→
138→    public async Task CmdResetAsync()
139→    {
140→        LastCmd = "에러 리셋";
141→        await WriteMw300Bit(5, true);
142→    }
143→
144→    /// <summary>
145→    /// 모든 명령 비트 OFF (MW300 = 0)
146→    /// </summary>
147→    public async Task CmdClearAsync()
148→    {
149→        await _client.WriteWordsAsync("%MW300", [0]);
150→        LastCmd = "명령 클리어 (MW300=0)";
151→    }
152→
153→    // === JOG (%UW0.9.1 직접 쓰기) ===
154→    public async Task JogCwAsync(bool on)
155→    {
156→        ushort val = (ushort)(on ? 0x0001 : 0x0000);
157→        await _client.WriteWordsAsync("%UW0.9.1", [val]);
158→        LastCmd = on ? "JOG CW ON" : "JOG OFF";
159→    }
160→
161→    public async Task JogCcwAsync(bool on)
162→    {
163→        ushort val = (ushort)(on ? 0x0002 : 0x0000);
164→        await _client.WriteWordsAsync("%UW0.9.1", [val]);
165→        LastCmd = on ? "JOG CCW ON" : "JOG OFF";
166→    }
167→
168→    // === 폴링 루프 ===
169→    private async Task PollLoopAsync(CancellationToken ct)
170→    {
171→        while (!ct.IsCancellationRequested)
172→        {
173→            var sw = System.Diagnostics.Stopwatch.StartNew();
174→            try
175→            {
176→                // 서보 상태 비트: MW400~401
177→                var sts = await _client.ReadWordsAsync("%MW400", 2);
178→                if (sts is { Length: >= 2 })
179→                {
180→                    Dispatch(() =>
181→                    {
182→                        _mw400Raw = sts[0]; _mw401Raw = sts[1];
183→                        StsMoving = (sts[0] & 0x0001) != 0;
184→                        StsError = (sts[0] & 0x0002) != 0;
185→                        StsRdy = (sts[0] & 0x0010) != 0;
186→                        StsServoMc = (sts[0] & 0x0040) != 0;
187→                        RspHomeDone = (sts[1] & 0x0001) != 0;
188→                        RspMoveDone = (sts[1] & 0x0002) != 0;
189→                        RspHomeErr = (sts[1] & 0x0004) != 0;
190→                        RspMoveErr = (sts[1] & 0x0008) != 0;
191→                        RspResetDone = (sts[1] & 0x0010) != 0;
192→                        N(nameof(Mw400Hex)); N(nameof(Mw401Hex));
193→                    });
194→                }
195→
196→                // 서보 값: MW410~414
197→                var vals = await _client.ReadWordsAsync("%MW410", 5);
198→                if (vals is { Length: >= 5 })
199→                {
200→                    Dispatch(() =>
201→                    {
202→                        ActPos = (int)(vals[0] | (vals[1] << 16));
203→                        ActVel = (int)(vals[2] | (vals[3] << 16));
204→                        ErrCode = vals[4];
205→                    });
206→                }
207→
208→                // U영역: %UW0.9.0 ~ %UW0.9.1 (슬롯9 모듈 상태 + JOG/DONE_CLR)
209→                var uArea = await _client.ReadWordsAsync("%UW0.9.0", 2);
210→                if (uArea is { Length: >= 2 })
211→                {
212→                    Dispatch(() =>
213→                    {
214→                        _uw090Raw = uArea[0]; _uw091Raw = uArea[1];
215→                        UPosEl = (uArea[0] & 0x0001) != 0;      // bit0: +EL
216→                        UNegEl = (uArea[0] & 0x0002) != 0;      // bit1: -EL
217→                        UDog = (uArea[0] & 0x0004) != 0;        // bit2: DOG
218→                        UZPhase = (uArea[0] & 0x0008) != 0;     // bit3: Z상
219→                        UOrgDone = (uArea[0] & 0x0010) != 0;    // bit4: ORG 완료
220→                        UDstDone = (uArea[0] & 0x0020) != 0;    // bit5: DST 완료
221→                        UModuleRdy = (uArea[0] & 0x8000) != 0;  // bit15: 모듈 RDY
222→                        N(nameof(Uw090Hex)); N(nameof(Uw091Hex));
223→                    });
224→                }
225→
226→                sw.Stop();
227→                Dispatch(() => CycleMs = (int)sw.ElapsedMilliseconds);
228→            }
229→            catch { /* 통신 에러 무시 — 다음 사이클 재시도 */ }
230→
231→            await Task.Delay(100, ct).ConfigureAwait(false);
232→        }
233→    }
234→
235→    // === 유틸 ===
236→    private async Task WriteMw300Bit(int bit, bool on)
237→    {
238→        if (!IsConnected) return;
239→        var words = await _client.ReadWordsAsync("%MW300", 1);
240→        ushort val = (words is { Length: > 0 }) ? words[0] : (ushort)0;
241→        if (on) val |= (ushort)(1 << bit);
242→        else val &= (ushort)~(1 << bit);
243→        await _client.WriteWordsAsync("%MW300", [val]);
244→    }
245→
246→    private static void Dispatch(Action a)
247→    {
248→        if (System.ComponentModel.DesignerProperties.GetIsInDesignMode(new System.Windows.DependencyObject()))
249→            return;
250→        Application.Current?.Dispatcher.Invoke(a);
251→    }
252→
253→    public void Dispose()
254→    {
255→        Disconnect();
256→        _client.Dispose();
257→    }
258→
259→    public event PropertyChangedEventHandler? PropertyChanged;
260→    private void N([CallerMemberName] string? n = null)
261→        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(n));
262→}
