(* ============================================================ *)
(* PROG_SERVO: 서보 모터 제어 (APM 위치결정 FB)                   *)
(* 역할: PC 명령 비트 → APM_xxx FB 실행 → 상태 비트 갱신          *)
(* 위치결정모듈: BASE=0, SLOT=9, AXIS=0 (XBF-PD02A)              *)
(* 서보 MC 릴레이: PC가 MW200.5 → IO_MAP → %QX0.0.5              *)
(* JOG: PC가 %UW0.9.1 직접 제어 (비트0=CW, 비트1=CCW)            *)
(* ============================================================ *)
(* [Fix1] INH_OFF := TRUE → 리셋 후 서보 출력 유지                *)
(* [Fix2] MW414=주요 에러, MW415=개별 FB 에러 구분 보고           *)
(* [Fix3] 원점/이동 타임아웃 (30초) → 무한 회전 방지              *)
(* [Fix4] CMD_RESET 시 이전 에러 상태 클리어                      *)
(* ============================================================ *)

(* SafetyStop 시 서보 긴급 정지 *)
IF g_SafetyStop THEN
    bOrgReq := FALSE;
    bDstReq := FALSE;
    bRstReq := FALSE;

    g_FB_StpEmo(REQ := TRUE, BASE := 0, SLOT := 9, AXIS := 0,
                DEC_TIME := 0, DONE => bStpDone, STAT => wStpStat);

    (* JOG 강제 OFF *)
    wJogWord := %UW0.9.1;
    wJogWord := wJogWord AND 16#FFFC;
    %UW0.9.1 := wJogWord;

    (* [Fix3] 타임아웃 타이머 리셋 *)
    tonOrgTimeout(IN := FALSE, PT := T#30s);
    tonDstTimeout(IN := FALSE, PT := T#30s);

    %MW400 := 16#0002;
    %MW401 := 0;
    g_bStopExec := TRUE;

ELSE

    (* 1. PC 명령 비트 읽기 (MW300) *)
    bCmdHome    := %MW300.0;
    bCmdMove    := %MW300.1;
    bCmdStop    := %MW300.4;
    bCmdReset   := %MW300.5;

    (* 제어 부가 비트 (MW301) *)
    bMoveRel    := %MW301.1;

    (* 2. 파라미터 읽기 (MW310~313, DINT = 2 WORD) *)
    dinTargetPos := WORD_TO_DINT(%MW310) + WORD_TO_DINT(%MW311) * 65536;
    dinTargetVel := WORD_TO_DINT(%MW312) + WORD_TO_DINT(%MW313) * 65536;

    (* 3. 수동 엣지 검출 *)
    bEdgeHome   := bCmdHome   AND NOT bPrevHome;
    bEdgeMove   := bCmdMove   AND NOT bPrevMove;
    bEdgeStop   := bCmdStop   AND NOT bPrevStop;
    bEdgeReset  := bCmdReset  AND NOT bPrevReset;

    bPrevHome   := bCmdHome;
    bPrevMove   := bCmdMove;
    bPrevStop   := bCmdStop;
    bPrevReset  := bCmdReset;

    (* 4. 원점복귀 — APM_ORG *)
    IF bEdgeHome THEN
        bOrgReq := TRUE;
        bOrgTimeout := FALSE;   (* [Fix3] 타임아웃 플래그 초기화 *)
    END_IF;

    g_FB_Org(REQ := bOrgReq, BASE := 0, SLOT := 9, AXIS := 0,
             DONE => bOrgDone, STAT => wOrgStat);

    (* [Fix3] 원점복귀 타임아웃 감시 (30초) *)
    tonOrgTimeout(IN := bOrgReq, PT := T#30s);
    IF tonOrgTimeout.Q THEN
        (* 30초 초과 → 강제 정지 + 에러 플래그 *)
        bOrgReq := FALSE;
        bOrgTimeout := TRUE;
    END_IF;

    IF bOrgDone OR (wOrgStat <> 0) THEN
        bOrgReq := FALSE;
    END_IF;

    (* 5. 위치 이동 — APM_DST *)
    IF bEdgeMove THEN
        bDstReq := TRUE;
        bDstTimeout := FALSE;   (* [Fix3] 타임아웃 플래그 초기화 *)
    END_IF;

    g_FB_Dst(REQ := bDstReq, BASE := 0, SLOT := 9, AXIS := 0,
             ADDR := dinTargetPos, SPEED := DINT_TO_UDINT(dinTargetVel),
             DWELL := 0, MCODE := 0,
             POS_SPD := FALSE, ABS_INC := bMoveRel,
             TIME_SEL := 0,
             DONE => bDstDone, STAT => wDstStat);

    (* [Fix3] 위치이동 타임아웃 감시 (30초) *)
    tonDstTimeout(IN := bDstReq, PT := T#30s);
    IF tonDstTimeout.Q THEN
        (* 30초 초과 → 강제 정지 + 에러 플래그 *)
        bDstReq := FALSE;
        bDstTimeout := TRUE;
    END_IF;

    IF bDstDone OR (wDstStat <> 0) THEN
        bDstReq := FALSE;
    END_IF;

    (* 6. 정지 — APM_STP *)
    IF bEdgeStop THEN
        bStpReq := TRUE;
    END_IF;

    g_FB_Stp(REQ := bStpReq, BASE := 0, SLOT := 9, AXIS := 0,
             DEC_TIME := 0, DONE => bStpDone, STAT => wStpStat);

    IF bStpDone OR (wStpStat <> 0) THEN
        bStpReq := FALSE;
    END_IF;

    (* 7. 폴트 리셋 — APM_RST *)
    (* [Fix1] INH_OFF := TRUE → 리셋 후에도 서보 출력 유지 *)
    IF bEdgeReset THEN
        bRstReq := TRUE;
    END_IF;

    g_FB_Rst(REQ := bRstReq, BASE := 0, SLOT := 9, AXIS := 0,
             INH_OFF := TRUE, DONE => bRstDone, STAT => wRstStat);

    IF bRstDone OR (wRstStat <> 0) THEN
        bRstReq := FALSE;
    END_IF;

    (* [Fix4] 리셋 완료 시 이전 에러 상태 클리어 *)
    IF bRstDone THEN
        wOrgStat := 0;
        wDstStat := 0;
        wStpStat := 0;
        bOrgTimeout := FALSE;
        bDstTimeout := FALSE;
    END_IF;

    (* 8. 서보 상태 비트 → MW400 *)
    wStatus := 0;
    wRdyStat := %UW0.9.0;

    (* bit0: 동작 중 *)
    IF bOrgReq OR bDstReq THEN
        wStatus := wStatus OR 16#0001;
    END_IF;
    (* bit1: 에러 발생 *)
    IF (wOrgStat <> 0) OR (wDstStat <> 0) OR (wStpStat <> 0) THEN
        wStatus := wStatus OR 16#0002;
    END_IF;
    (* bit2: 타임아웃 에러 [Fix3] *)
    IF bOrgTimeout OR bDstTimeout THEN
        wStatus := wStatus OR 16#0004;
    END_IF;
    (* bit4: 위치결정모듈 RDY (비트15) *)
    IF (wRdyStat AND 16#8000) <> 16#0000 THEN
        wStatus := wStatus OR 16#0010;
    END_IF;
    (* bit6: 서보MC 출력 상태 *)
    IF %QX0.0.5 THEN
        wStatus := wStatus OR 16#0040;
    END_IF;

    %MW400 := wStatus;

    (* 9. 명령 응답 비트 → MW401 *)
    wResponse := 0;

    IF bOrgDone THEN
        wResponse := wResponse OR 16#0001;
    END_IF;
    IF bDstDone THEN
        wResponse := wResponse OR 16#0002;
    END_IF;
    IF wOrgStat <> 0 THEN
        wResponse := wResponse OR 16#0004;
    END_IF;
    IF wDstStat <> 0 THEN
        wResponse := wResponse OR 16#0008;
    END_IF;
    IF bRstDone THEN
        wResponse := wResponse OR 16#0010;
    END_IF;
    (* bit5: 원점 타임아웃 [Fix3] *)
    IF bOrgTimeout THEN
        wResponse := wResponse OR 16#0020;
    END_IF;
    (* bit6: 이동 타임아웃 [Fix3] *)
    IF bDstTimeout THEN
        wResponse := wResponse OR 16#0040;
    END_IF;

    %MW401 := wResponse;

    (* 10. 위치/속도 → MW410~415 (U영역 직접 복사) *)
    %MW410 := %UW0.9.2;   (* 현재 위치 하위 *)
    %MW411 := %UW0.9.3;   (* 현재 위치 상위 *)
    %MW412 := %UW0.9.4;   (* 현재 속도 하위 *)
    %MW413 := %UW0.9.5;   (* 현재 속도 상위 *)

    (* [Fix2] MW414: 현재 활성 FB 에러 코드 (진단용 — 우선순위 분리) *)
    IF wOrgStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wOrgStat);       (* 원점복귀 에러 우선 *)
    ELSIF wDstStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wDstStat);       (* 위치이동 에러 *)
    ELSIF wStpStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wStpStat);       (* 정지 에러 *)
    ELSIF wRstStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wRstStat);       (* 리셋 에러 *)
    ELSE
        %MW414 := 0;
    END_IF;

    (* [Fix2] MW415: 개별 FB 에러 소스 비트맵 *)
    (* bit0: ORG에러, bit1: DST에러, bit2: STP에러, bit3: RST에러 *)
    (* bit4: ORG타임아웃, bit5: DST타임아웃 *)
    wErrSource := 0;
    IF wOrgStat <> 0 THEN
        wErrSource := wErrSource OR 16#0001;
    END_IF;
    IF wDstStat <> 0 THEN
        wErrSource := wErrSource OR 16#0002;
    END_IF;
    IF wStpStat <> 0 THEN
        wErrSource := wErrSource OR 16#0004;
    END_IF;
    IF wRstStat <> 0 THEN
        wErrSource := wErrSource OR 16#0008;
    END_IF;
    IF bOrgTimeout THEN
        wErrSource := wErrSource OR 16#0010;
    END_IF;
    IF bDstTimeout THEN
        wErrSource := wErrSource OR 16#0020;
    END_IF;
    %MW415 := wErrSource;

END_IF;

