// ======== JOG 제어 — %UW0.9.1 직접 쓰기 ========

/// <summary>
/// JOG 시작 (CW=정방향, CCW=역방향)
/// %UW0.9.1: bit0=CW, bit1=CCW
/// </summary>
public async Task JogStartAsync(bool isCw)
{
    if (!IsConnected) return;
    ushort jogVal = isCw ? (ushort)0x0001 : (ushort)0x0002;
    await _client.WriteWordsAsync("%UW0.9.1", [jogVal]);
    LastServoCmd = isCw ? "JOG CW ON" : "JOG CCW ON";
}

/// <summary>
/// JOG 정지 — %UW0.9.1 = 0
/// </summary>
public async Task JogStopAsync()
{
    if (!IsConnected) return;
    await _client.WriteWordsAsync("%UW0.9.1", [0x0000]);
    LastServoCmd = "JOG OFF";
}

// ======== 서보 명령 — MW300 비트 펄스 (SET → 500ms → CLEAR) ========

/// <summary>
/// MW300 특정 비트를 펄스로 ON → 대기 → OFF
/// </summary>
private async Task SendServoCommandAsync(int bit)
{
    if (!IsConnected) return;
    // 현재 MW300 읽기 → 비트 SET → 쓰기 → 대기 → 비트 CLEAR → 쓰기
    var current = await _client.ReadWordsAsync("%MW300", 1);
    ushort val = (current is { Length: > 0 }) ? current[0] : (ushort)0;
    ushort newVal = (ushort)(val | (1 << bit));
    await _client.WriteWordsAsync("%MW300", [newVal]);
    await Task.Delay(500);
    newVal = (ushort)(val & ~(1 << bit));
    await _client.WriteWordsAsync("%MW300", [newVal]);
}

/// <summary>원점복귀 = MW300.bit0</summary>
public async Task HomeAsync()
{
    LastServoCmd = "원점복귀 실행...";
    await SendServoCommandAsync(0);
}

/// <summary>위치이동 = MW300.bit1 (파라미터 MW310~313 사전 쓰기)</summary>
public async Task MoveAsync()
{
    if (!int.TryParse(TargetPosInput, out var pos) ||
        !int.TryParse(TargetVelInput, out var vel))
    {
        LastServoCmd = "파라미터 입력 오류 (정수 필요)";
        return;
    }

    // MW301.1: 절대/상대 이동 모드
    ushort mw301 = (ushort)(IsMoveRel ? 0x0002 : 0x0000);
    await _client.WriteWordsAsync("%MW301", [mw301]);

    // MW310~313: 목표위치(DINT) + 목표속도(DINT)
    ushort posL = (ushort)(pos & 0xFFFF);
    ushort posH = (ushort)((pos >> 16) & 0xFFFF);
    ushort velL = (ushort)(vel & 0xFFFF);
    ushort velH = (ushort)((vel >> 16) & 0xFFFF);
    await _client.WriteWordsAsync("%MW310", [posL, posH, velL, velH]);

    LastServoCmd = $"이동: pos={pos}, vel={vel}, {(IsMoveRel ? "상대" : "절대")}";
    await SendServoCommandAsync(1);
}

/// <summary>즉시정지 = MW300.bit4</summary>
public async Task StopAsync()
{
    LastServoCmd = "즉시정지";
    await SendServoCommandAsync(4);
}

/// <summary>에러리셋 = MW300.bit5</summary>
public async Task ResetAsync()
{
    LastServoCmd = "에러 리셋";
    await SendServoCommandAsync(5);
}

