 95→
 96→    (* [Fix3] 위치이동 타임아웃 감시 (30초) *)
 97→    tonDstTimeout(IN := bDstReq, PT := T#30s);
 98→    IF tonDstTimeout.Q THEN
 99→        bDstReq := FALSE;
100→        bDstTimeout := TRUE;
101→    END_IF;
102→
103→    IF bDstDone OR (wDstStat <> 0) THEN
104→        bDstReq := FALSE;
105→    END_IF;
106→
107→    (* 6. 정지 — APM_STP *)
