135→             DONE => bFltDone, STAT => wFltStat);
136→
137→    IF bFltDone THEN
138→        bFltReq := FALSE;
139→        bRstReq := TRUE;
140→    END_IF;
141→
142→    (* [Fix1] 서보 리셋 — INH_OFF := TRUE (출력 유지) *)
143→    g_FB_Rst(REQ := bRstReq, BASE := 0, SLOT := 9, AXIS := 0,
144→             INH_OFF := TRUE, DONE => bRstDone, STAT => wRstStat);
145→
146→    IF bRstDone OR (wRstStat <> 0) THEN
147→        bRstReq := FALSE;
148→    END_IF;
149→
150→    (* [Fix4] 리셋 완료 후 잔여 에러 재확인 클리어 *)
151→    IF bRstDone THEN
152→        wOrgStat := 0;
153→        wDstStat := 0;
