public IoMonitorViewModel()
{
    foreach (var w in MemoryMapDefinition.InputMap)
        InputWords.Add(new WordViewModel(w));

    foreach (var w in MemoryMapDefinition.OutputMap)
        OutputWords.Add(new WordViewModel(w));

    foreach (var w in MemoryMapDefinition.ServoAndSystemMap)
        ServoSystemWords.Add(new WordViewModel(w));

    // JSON에서 사용자 편집 이름 로드
    IoMapConfig.Load(InputWords, OutputWords, ServoSystemWords);
}

/// <summary>
/// 사용자 편집 이름 JSON 저장
/// </summary>
public void SaveBitNames()
{
    IoMapConfig.Save(InputWords, OutputWords, ServoSystemWords);
}

public async Task ConnectAndStartAsync()
{
    ConnectionStatus = "연결 중...";
    var ok = await _client.ConnectAsync();
    if (!ok)
    {
        ConnectionStatus = $"연결 실패 ({_client.IpAddress}:{_client.Port})";
        IsConnected = false;
        return;
    }

    IsConnected = true;
    ConnectionStatus = $"연결됨 ({_client.IpAddress})";

    _cts = new CancellationTokenSource();
    _ = Task.Run(() => PollLoopAsync(_cts.Token));
}

public async void StopAndDisconnect()
{
    _cts?.Cancel();

    // PC_READY OFF 전송 후 해제
    if (_client.IsConnected)
    {
        try { await _client.WriteWordsAsync("%MW500", [0]); }
        catch { /* 무시 */ }
    }

    _client.Disconnect();
    IsConnected = false;
    PlcCommOk = false;
    PlcRun = false;
    ConnectionStatus = "미연결";
}

/// <summary>
/// 출력 비트 토글 — 클릭 시 호출
/// </summary>
public async Task ToggleOutputBitAsync(int wordIndex, int bitIndex)
{
    if (!IsConnected || wordIndex < 0 || wordIndex >= 10) return;

    // 현재 캐시 값에서 비트 토글
    _outputCache[wordIndex] ^= (ushort)(1 << bitIndex);

    // 해당 WORD 1개만 쓰기 (MW200 + wordIndex)
    var address = $"%MW{200 + wordIndex}";
    await _client.WriteWordsAsync(address, [_outputCache[wordIndex]]);
}

/// <summary>
/// 서보/시스템 WRITE 영역 비트 토글 (MW300,301,500)
/// </summary>
public async Task ToggleServoSystemBitAsync(int wordIndex, int bitIndex)
{
    if (!IsConnected || wordIndex < 0 || wordIndex >= ServoSysMwAddresses.Length) return;

    // WRITE 방향인지 확인
    if (wordIndex < ServoSystemWords.Count && ServoSystemWords[wordIndex].Direction != "WRITE") return;

    _servoSysCache[wordIndex] ^= (ushort)(1 << bitIndex);

    var address = $"%MW{ServoSysMwAddresses[wordIndex]}";
    await _client.WriteWordsAsync(address, [_servoSysCache[wordIndex]]);
}

