226→    /// <summary>
227→    /// MW300 특정 비트를 펄스로 ON → 대기 → OFF
228→    /// </summary>
229→    private async Task SendServoCommandAsync(int bit)
230→    {
231→        if (!IsConnected) return;
232→        // 현재 MW300 읽기 → 비트 SET → 쓰기 → 대기 → 비트 CLEAR → 쓰기
233→        var current = await _client.ReadWordsAsync("%MW300", 1);
234→        ushort val = (current is { Length: > 0 }) ? current[0] : (ushort)0;
235→        ushort newVal = (ushort)(val | (1 << bit));
236→        await _client.WriteWordsAsync("%MW300", [newVal]);
237→        await Task.Delay(500);
238→        newVal = (ushort)(val & ~(1 << bit));
239→        await _client.WriteWordsAsync("%MW300", [newVal]);
240→    }
