  1→using System;
  2→using System.Collections.ObjectModel;
  3→using System.ComponentModel;
  4→using System.Runtime.CompilerServices;
  5→using System.Threading;
  6→using System.Threading.Tasks;
  7→using System.Windows;
  8→using AssembleMonitor.Features.Communication;
  9→using AssembleMonitor.Models;
 10→using static AssembleMonitor.Features.IoMonitor.MemoryMapDefinition;
 11→
 12→namespace AssembleMonitor.Features.IoMonitor;
 13→
 14→/// <summary>
 15→/// I/O 모니터 뷰모델 — PLC 비트 데이터 실시간 표시 + 출력 제어
 16→/// </summary>
 17→public class IoMonitorViewModel : INotifyPropertyChanged, IDisposable
 18→{
 19→    private readonly XgtClient _client = new();
 20→    private CancellationTokenSource? _cts;
 21→
 22→    // 탭별 WORD 데이터
 23→    public ObservableCollection<WordViewModel> InputWords { get; } = [];
 24→    public ObservableCollection<WordViewModel> OutputWords { get; } = [];
 25→    public ObservableCollection<WordViewModel> ServoSystemWords { get; } = [];
 26→
 27→    // 출력 캐시 — 토글 시 현재 값 기반으로 비트 변경 후 쓰기
 28→    private readonly ushort[] _outputCache = new ushort[10];
 29→
 30→    // 서보/시스템 WRITE 캐시 — MW300,301,500 (ServoSystemWords index 0,1,4)
 31→    private readonly ushort[] _servoSysCache = new ushort[6];
 32→    // ServoSystemWords 인덱스 → MW 주소 매핑
 33→    private static readonly int[] ServoSysMwAddresses = [300, 301, 400, 401, 500, 501];
 34→
 35→    // 서보 파라미터 (DINT 값)
 36→    private int _targetPos, _targetVel, _jogVel, _actPos, _actVel;
 37→    private ushort _errCode, _actPosDeg;
 38→
 39→    public int TargetPos { get => _targetPos; set { _targetPos = value; OnPropertyChanged(); } }
 40→    public int TargetVel { get => _targetVel; set { _targetVel = value; OnPropertyChanged(); } }
 41→    public int JogVel { get => _jogVel; set { _jogVel = value; OnPropertyChanged(); } }
 42→    public int ActPos { get => _actPos; set { _actPos = value; OnPropertyChanged(); OnPropertyChanged(nameof(ActPosDegStr)); } }
 43→    public int ActVel { get => _actVel; set { _actVel = value; OnPropertyChanged(); } }
 44→    public ushort ErrCode { get => _errCode; set { _errCode = value; OnPropertyChanged(); } }
 45→    public ushort ActPosDeg { get => _actPosDeg; set { _actPosDeg = value; OnPropertyChanged(); } }
 46→    public string ActPosDegStr => $"{ActPos / 1000.0:F3}°";
 47→
 48→    // U영역 모니터 (%UW0.9.0 ~ %UW0.9.1)
 49→    private ushort _uw090Raw, _uw091Raw;
 50→    private bool _uModuleRdy, _uPosEl, _uNegEl, _uDog, _uZPhase, _uOrgDone, _uDstDone;
 51→
 52→    public bool UModuleRdy { get => _uModuleRdy; set { _uModuleRdy = value; OnPropertyChanged(); } }
 53→    public bool UPosEl { get => _uPosEl; set { _uPosEl = value; OnPropertyChanged(); } }
 54→    public bool UNegEl { get => _uNegEl; set { _uNegEl = value; OnPropertyChanged(); } }
 55→    public bool UDog { get => _uDog; set { _uDog = value; OnPropertyChanged(); } }
 56→    public bool UZPhase { get => _uZPhase; set { _uZPhase = value; OnPropertyChanged(); } }
 57→    public bool UOrgDone { get => _uOrgDone; set { _uOrgDone = value; OnPropertyChanged(); } }
 58→    public bool UDstDone { get => _uDstDone; set { _uDstDone = value; OnPropertyChanged(); } }
 59→    public string Uw090Hex => $"0x{_uw090Raw:X4}";
 60→    public string Uw091Hex => $"0x{_uw091Raw:X4}";
 61→
 62→    // 서보 제어 상태
 63→    private bool _stsMoving, _stsError, _stsRdy;
 64→    private bool _rspHomeDone, _rspMoveDone, _rspHomeErr, _rspMoveErr, _rspResetDone;
 65→    private string _lastServoCmd = "";
 66→
 67→    public bool StsMoving { get => _stsMoving; set { _stsMoving = value; OnPropertyChanged(); } }
 68→    public bool StsError { get => _stsError; set { _stsError = value; OnPropertyChanged(); } }
 69→    public bool StsRdy { get => _stsRdy; set { _stsRdy = value; OnPropertyChanged(); } }
 70→    public bool RspHomeDone { get => _rspHomeDone; set { _rspHomeDone = value; OnPropertyChanged(); } }
 71→    public bool RspMoveDone { get => _rspMoveDone; set { _rspMoveDone = value; OnPropertyChanged(); } }
 72→    public bool RspHomeErr { get => _rspHomeErr; set { _rspHomeErr = value; OnPropertyChanged(); } }
 73→    public bool RspMoveErr { get => _rspMoveErr; set { _rspMoveErr = value; OnPropertyChanged(); } }
 74→    public bool RspResetDone { get => _rspResetDone; set { _rspResetDone = value; OnPropertyChanged(); } }
 75→    public string LastServoCmd { get => _lastServoCmd; set { _lastServoCmd = value; OnPropertyChanged(); } }
 76→
 77→    // 서보 파라미터 입력
 78→    private string _targetPosInput = "0";
 79→    private string _targetVelInput = "10000";
 80→    private bool _isMoveRel;
 81→
 82→    public string TargetPosInput { get => _targetPosInput; set { _targetPosInput = value; OnPropertyChanged(); } }
 83→    public string TargetVelInput { get => _targetVelInput; set { _targetVelInput = value; OnPropertyChanged(); } }
 84→    public bool IsMoveRel { get => _isMoveRel; set { _isMoveRel = value; OnPropertyChanged(); } }
 85→
 86→    // Heartbeat 카운터 (MW500: bit0~7=카운터, bit8=PC_READY)
 87→    private byte _heartbeatCount;
 88→
 89→    // PLC 상태 (MW501 파싱)
 90→    private bool _plcCommOk, _plcEmoActive, _plcServoErr, _plcWdTimeout, _plcRun;
 91→    private byte _plcHeartbeat;
 92→
 93→    public bool PlcCommOk { get => _plcCommOk; set { _plcCommOk = value; OnPropertyChanged(); } }
 94→    public bool PlcEmoActive { get => _plcEmoActive; set { _plcEmoActive = value; OnPropertyChanged(); } }
 95→    public bool PlcServoErr { get => _plcServoErr; set { _plcServoErr = value; OnPropertyChanged(); } }
 96→    public bool PlcWdTimeout { get => _plcWdTimeout; set { _plcWdTimeout = value; OnPropertyChanged(); } }
 97→    public bool PlcRun { get => _plcRun; set { _plcRun = value; OnPropertyChanged(); } }
 98→    public byte PlcHeartbeat { get => _plcHeartbeat; set { _plcHeartbeat = value; OnPropertyChanged(); } }
 99→
100→    // 연결 상태
101→    private string _connectionStatus = "미연결";
102→    private bool _isConnected;
103→    private int _cycleMs;
104→
105→    public string ConnectionStatus { get => _connectionStatus; set { _connectionStatus = value; OnPropertyChanged(); } }
106→    public bool IsConnected { get => _isConnected; set { _isConnected = value; OnPropertyChanged(); } }
107→    public int CycleMs { get => _cycleMs; set { _cycleMs = value; OnPropertyChanged(); } }
108→
109→
110→    public IoMonitorViewModel()
111→    {
112→        foreach (var w in MemoryMapDefinition.InputMap)
113→            InputWords.Add(new WordViewModel(w));
114→
115→        foreach (var w in MemoryMapDefinition.OutputMap)
116→            OutputWords.Add(new WordViewModel(w));
117→
118→        foreach (var w in MemoryMapDefinition.ServoAndSystemMap)
119→            ServoSystemWords.Add(new WordViewModel(w));
120→
121→        // JSON에서 사용자 편집 이름 로드
122→        IoMapConfig.Load(InputWords, OutputWords, ServoSystemWords);
123→    }
124→
125→    /// <summary>
126→    /// 사용자 편집 이름 JSON 저장
127→    /// </summary>
128→    public void SaveBitNames()
129→    {
130→        IoMapConfig.Save(InputWords, OutputWords, ServoSystemWords);
131→    }
132→
133→    public async Task ConnectAndStartAsync()
134→    {
135→        ConnectionStatus = "연결 중...";
136→        var ok = await _client.ConnectAsync();
137→        if (!ok)
138→        {
139→            ConnectionStatus = $"연결 실패 ({_client.IpAddress}:{_client.Port})";
140→            IsConnected = false;
141→            return;
142→        }
143→
144→        IsConnected = true;
145→        ConnectionStatus = $"연결됨 ({_client.IpAddress})";
146→
147→        _cts = new CancellationTokenSource();
148→        _ = Task.Run(() => PollLoopAsync(_cts.Token));
149→    }
150→
151→    public async void StopAndDisconnect()
152→    {
153→        _cts?.Cancel();
154→
155→        // PC_READY OFF 전송 후 해제
156→        if (_client.IsConnected)
157→        {
158→            try { await _client.WriteWordsAsync("%MW500", [0]); }
159→            catch { /* 무시 */ }
160→        }
161→
162→        _client.Disconnect();
163→        IsConnected = false;
164→        PlcCommOk = false;
165→        PlcRun = false;
166→        ConnectionStatus = "미연결";
167→    }
168→
169→    /// <summary>
170→    /// 출력 비트 토글 — 클릭 시 호출
171→    /// </summary>
172→    public async Task ToggleOutputBitAsync(int wordIndex, int bitIndex)
173→    {
174→        if (!IsConnected || wordIndex < 0 || wordIndex >= 10) return;
175→
176→        // 현재 캐시 값에서 비트 토글
177→        _outputCache[wordIndex] ^= (ushort)(1 << bitIndex);
178→
179→        // 해당 WORD 1개만 쓰기 (MW200 + wordIndex)
180→        var address = $"%MW{200 + wordIndex}";
181→        await _client.WriteWordsAsync(address, [_outputCache[wordIndex]]);
182→    }
183→
184→    /// <summary>
185→    /// 서보/시스템 WRITE 영역 비트 토글 (MW300,301,500)
186→    /// </summary>
187→    public async Task ToggleServoSystemBitAsync(int wordIndex, int bitIndex)
188→    {
189→        if (!IsConnected || wordIndex < 0 || wordIndex >= ServoSysMwAddresses.Length) return;
190→
191→        // WRITE 방향인지 확인
192→        if (wordIndex < ServoSystemWords.Count && ServoSystemWords[wordIndex].Direction != "WRITE") return;
193→
194→        _servoSysCache[wordIndex] ^= (ushort)(1 << bitIndex);
195→
196→        var address = $"%MW{ServoSysMwAddresses[wordIndex]}";
197→        await _client.WriteWordsAsync(address, [_servoSysCache[wordIndex]]);
198→    }
199→
200→    // ======== JOG 제어 — %UW0.9.1 직접 쓰기 ========
201→
202→    /// <summary>
203→    /// JOG 시작 (CW=정방향, CCW=역방향)
204→    /// %UW0.9.1: bit0=CW, bit1=CCW
205→    /// </summary>
206→    public async Task JogStartAsync(bool isCw)
207→    {
208→        if (!IsConnected) return;
209→        ushort jogVal = isCw ? (ushort)0x0001 : (ushort)0x0002;
210→        await _client.WriteWordsAsync("%UW0.9.1", [jogVal]);
211→        LastServoCmd = isCw ? "JOG CW ON" : "JOG CCW ON";
212→    }
213→
214→    /// <summary>
215→    /// JOG 정지 — %UW0.9.1 = 0
216→    /// </summary>
217→    public async Task JogStopAsync()
218→    {
219→        if (!IsConnected) return;
220→        await _client.WriteWordsAsync("%UW0.9.1", [0x0000]);
221→        LastServoCmd = "JOG OFF";
222→    }
223→
224→    // ======== 서보 명령 — MW300 비트 펄스 (SET → 500ms → CLEAR) ========
225→
226→    /// <summary>
227→    /// MW300 특정 비트를 펄스로 ON → 대기 → OFF
228→    /// </summary>
229→    private async Task SendServoCommandAsync(int bit)
230→    {
231→        if (!IsConnected) return;
232→        // 현재 MW300 읽기 → 비트 SET → 쓰기 → 대기 → 비트 CLEAR → 쓰기
233→        var current = await _client.ReadWordsAsync("%MW300", 1);
234→        ushort val = (current is { Length: > 0 }) ? current[0] : (ushort)0;
235→        ushort newVal = (ushort)(val | (1 << bit));
236→        await _client.WriteWordsAsync("%MW300", [newVal]);
237→        await Task.Delay(500);
238→        newVal = (ushort)(val & ~(1 << bit));
239→        await _client.WriteWordsAsync("%MW300", [newVal]);
240→    }
241→
242→    /// <summary>원점복귀 = MW300.bit0</summary>
243→    public async Task HomeAsync()
244→    {
245→        LastServoCmd = "원점복귀 실행...";
246→        await SendServoCommandAsync(0);
247→    }
248→
249→    /// <summary>위치이동 = MW300.bit1 (파라미터 MW310~313 사전 쓰기)</summary>
250→    public async Task MoveAsync()
251→    {
252→        if (!int.TryParse(TargetPosInput, out var pos) ||
253→            !int.TryParse(TargetVelInput, out var vel))
254→        {
255→            LastServoCmd = "파라미터 입력 오류 (정수 필요)";
256→            return;
257→        }
258→
259→        // MW301.1: 절대/상대 이동 모드
260→        ushort mw301 = (ushort)(IsMoveRel ? 0x0002 : 0x0000);
261→        await _client.WriteWordsAsync("%MW301", [mw301]);
262→
263→        // MW310~313: 목표위치(DINT) + 목표속도(DINT)
264→        ushort posL = (ushort)(pos & 0xFFFF);
265→        ushort posH = (ushort)((pos >> 16) & 0xFFFF);
266→        ushort velL = (ushort)(vel & 0xFFFF);
267→        ushort velH = (ushort)((vel >> 16) & 0xFFFF);
268→        await _client.WriteWordsAsync("%MW310", [posL, posH, velL, velH]);
269→
270→        LastServoCmd = $"이동: pos={pos}, vel={vel}, {(IsMoveRel ? "상대" : "절대")}";
271→        await SendServoCommandAsync(1);
272→    }
273→
274→    /// <summary>즉시정지 = MW300.bit4</summary>
275→    public async Task StopAsync()
276→    {
277→        LastServoCmd = "즉시정지";
278→        await SendServoCommandAsync(4);
279→    }
280→
281→    /// <summary>에러리셋 = MW300.bit5</summary>
282→    public async Task ResetAsync()
283→    {
284→        LastServoCmd = "에러 리셋";
285→        await SendServoCommandAsync(5);
286→    }
287→
288→    /// <summary>
289→    /// 주기적으로 PLC MW 영역 읽기 + Heartbeat 쓰기
290→    /// </summary>
291→    private async Task PollLoopAsync(CancellationToken ct)
292→    {
293→        while (!ct.IsCancellationRequested)
294→        {
295→            var sw = System.Diagnostics.Stopwatch.StartNew();
296→            try
297→            {
298→                // ★ Heartbeat 쓰기 — 매 사이클 최우선 (연결 중 무조건)
299→                _heartbeatCount++;
300→                ushort heartbeat = (ushort)(_heartbeatCount | 0x0100); // bit8=PC_READY
301→                await _client.WriteWordsAsync("%MW500", [heartbeat]);
302→
303→                // 입력 읽기: MW100~109 (10 WORD)
304→                var inputs = await _client.ReadWordsAsync("%MW100", 10);
305→                if (inputs != null)
306→                    UpdateWordViewModels(InputWords, inputs);
307→
308→                // 출력 읽기: MW200~209 (10 WORD) — readback
309→                var outputs = await _client.ReadWordsAsync("%MW200", 10);
310→                if (outputs != null)
311→                {
312→                    // 출력 캐시 동기화 (PLC에서 읽은 값 반영)
313→                    Array.Copy(outputs, _outputCache, Math.Min(outputs.Length, 10));
314→                    UpdateWordViewModels(OutputWords, outputs);
315→                }
316→
317→                // 서보 명령 읽기: MW300~301 (2 WORD)
318→                var servoCmds = await _client.ReadWordsAsync("%MW300", 2);
319→
320→                // 서보 파라미터 읽기: MW310~319 (10 WORD)
321→                var servoParams = await _client.ReadWordsAsync("%MW310", 10);
322→
323→                // 서보 상태 읽기: MW400~401 (2 WORD)
324→                var servoStatus = await _client.ReadWordsAsync("%MW400", 2);
325→
326→                // 서보 값 읽기: MW410~415 (6 WORD)
327→                var servoValues = await _client.ReadWordsAsync("%MW410", 6);
328→
329→                // 시스템 읽기: MW500~501 (2 WORD)
330→                var system = await _client.ReadWordsAsync("%MW500", 2);
331→
332→                // MW501 파싱 — PLC 상태 비트 + PLC 하트비트
333→                if (system is { Length: >= 2 })
334→                {
335→                    var mw501 = system[1];
336→                    Application.Current?.Dispatcher.Invoke(() =>
337→                    {
338→                        PlcCommOk = (mw501 & 0x0001) != 0;
339→                        PlcEmoActive = (mw501 & 0x0002) != 0;
340→                        PlcServoErr = (mw501 & 0x0004) != 0;
341→                        PlcWdTimeout = (mw501 & 0x0008) != 0;
342→                        PlcRun = (mw501 & 0x0010) != 0;
343→                        PlcHeartbeat = (byte)(mw501 >> 8);
344→                    });
345→                }
346→
347→                // 서보/시스템 탭 업데이트 + WRITE 캐시 동기화
348→                var servoSysData = new ushort[6];
349→                if (servoCmds != null) { servoSysData[0] = servoCmds[0]; servoSysData[1] = servoCmds[1]; }
350→                if (servoStatus != null) { servoSysData[2] = servoStatus[0]; servoSysData[3] = servoStatus[1]; }
351→                if (system != null) { servoSysData[4] = system[0]; servoSysData[5] = system[1]; }
352→                Array.Copy(servoSysData, _servoSysCache, 6);
353→                UpdateWordViewModels(ServoSystemWords, servoSysData);
354→
355→                // 서보 파라미터/값 (DINT) 업데이트
356→                if (servoParams is { Length: >= 6 })
357→                {
358→                    Application.Current?.Dispatcher.Invoke(() =>
359→                    {
360→                        TargetPos = (int)(servoParams[0] | (servoParams[1] << 16));
361→                        TargetVel = (int)(servoParams[2] | (servoParams[3] << 16));
362→                        JogVel = (int)(servoParams[4] | (servoParams[5] << 16));
363→                    });
364→                }
365→                if (servoValues is { Length: >= 6 })
366→                {
367→                    Application.Current?.Dispatcher.Invoke(() =>
368→                    {
369→                        ActPos = (int)(servoValues[0] | (servoValues[1] << 16));
370→                        ActVel = (int)(servoValues[2] | (servoValues[3] << 16));
371→                        ErrCode = servoValues[4];
372→                        ActPosDeg = servoValues[5];
373→                    });
374→                }
375→
376→                // 서보 상태 비트 파싱 (MW400: 상태, MW401: 응답)
377→                if (servoStatus is { Length: >= 2 })
378→                {
379→                    Application.Current?.Dispatcher.Invoke(() =>
380→                    {
381→                        StsMoving = (servoStatus[0] & 0x0001) != 0;
382→                        StsError = (servoStatus[0] & 0x0002) != 0;
383→                        StsRdy = (servoStatus[0] & 0x0010) != 0;
384→                        RspHomeDone = (servoStatus[1] & 0x0001) != 0;
385→                        RspMoveDone = (servoStatus[1] & 0x0002) != 0;
386→                        RspHomeErr = (servoStatus[1] & 0x0004) != 0;
387→                        RspMoveErr = (servoStatus[1] & 0x0008) != 0;
388→                        RspResetDone = (servoStatus[1] & 0x0010) != 0;
389→                    });
390→                }
391→
392→                // U영역 모듈 상태 읽기: %UW0.9.0 ~ %UW0.9.1 (슬롯9 위치결정 모듈)
393→                var uwData = await _client.ReadWordsAsync("%UW0.9.0", 2);
394→                if (uwData is { Length: >= 2 })
395→                {
396→                    Application.Current?.Dispatcher.Invoke(() =>
397→                    {
398→                        _uw090Raw = uwData[0]; _uw091Raw = uwData[1];
399→                        UPosEl = (uwData[0] & 0x0001) != 0;      // bit0: +EL (상한)
400→                        UNegEl = (uwData[0] & 0x0002) != 0;      // bit1: -EL (하한)
401→                        UDog = (uwData[0] & 0x0004) != 0;        // bit2: DOG (근사원점)
402→                        UZPhase = (uwData[0] & 0x0008) != 0;     // bit3: Z상
403→                        UOrgDone = (uwData[0] & 0x0010) != 0;    // bit4: ORG 완료
404→                        UDstDone = (uwData[0] & 0x0020) != 0;    // bit5: DST 완료
405→                        UModuleRdy = (uwData[0] & 0x8000) != 0;  // bit15: 모듈 RDY
406→                        OnPropertyChanged(nameof(Uw090Hex));
407→                        OnPropertyChanged(nameof(Uw091Hex));
408→                    });
409→                }
410→
411→                sw.Stop();
412→                Application.Current?.Dispatcher.Invoke(() =>
413→                {
414→                    CycleMs = (int)sw.ElapsedMilliseconds;
415→                    var plcSts = PlcRun ? "RUN" : (PlcWdTimeout ? "WD!" : "---");
416→                    ConnectionStatus = $"연결됨 ({_client.IpAddress}) — {CycleMs}ms | PC:{_heartbeatCount} PLC:{PlcHeartbeat} | {plcSts}";
417→                });
418→            }
419→            catch (Exception ex)
420→            {
421→                Application.Current?.Dispatcher.Invoke(() =>
422→                {
423→                    ConnectionStatus = $"통신 에러: {ex.Message}";
424→                });
425→            }
426→
427→            // Delay 없음 — 통신 사이클(~50ms) 자체가 주기
428→            await Task.Yield();
429→        }
430→    }
431→
432→    private void UpdateWordViewModels(ObservableCollection<WordViewModel> vms, ushort[] data)
433→    {
434→        Application.Current?.Dispatcher.Invoke(() =>
435→        {
436→            for (int i = 0; i < Math.Min(vms.Count, data.Length); i++)
437→                vms[i].UpdateValue(data[i]);
438→        });
439→    }
440→
441→
442→    public void Dispose()
443→    {
444→        StopAndDisconnect();
445→        _client.Dispose();
446→    }
