(* ============================================================ *)
(* PROG_SERVO: 서보 모터 제어 (APM 위치결정 FB)                   *)
(* 역할: PC 명령 비트 -> APM_xxx FB 실행 -> 상태 비트 갱신         *)
(* 위치결정모듈: BASE=0, SLOT=9, AXIS=0 (XBF-PD02A)              *)
(* 서보 MC 릴레이: PC가 MW200.5 -> IO_MAP -> %QX0.0.5             *)
(* ============================================================ *)
(* MW300 비트 할당:                                                *)
(*   bit0=HOME, bit1=MOVE, bit4=STOP, bit5=RESET                  *)
(*   bit6=JOG_CW, bit7=JOG_CCW (APM_JOG FB 사용)                  *)
(* MW301.2: JOG HIGH/LOW (0=저속, 1=고속)                         *)
(* ============================================================ *)

(* SafetyStop 시 서보 긴급 정지 *)
IF g_SafetyStop THEN
    bOrgReq := FALSE;
    bDstReq := FALSE;
    bRstReq := FALSE;
    bJogReq := FALSE;

    g_FB_StpEmo(REQ := TRUE, BASE := 0, SLOT := 9, AXIS := 0,
                DEC_TIME := 0, DONE => bStpDone, STAT => wStpStat);

    (* 타임아웃 타이머 리셋 *)
    tonOrgTimeout(IN := FALSE, PT := T#30s);
    tonDstTimeout(IN := FALSE, PT := T#30s);

    %MW400 := 16#0002;
    %MW401 := 0;
    g_bStopExec := TRUE;

ELSE

    (* 1. PC 명령 비트 읽기 (MW300) *)
    bCmdHome    := %MW300.0;
    bCmdMove    := %MW300.1;
    bCmdStop    := %MW300.4;
    bCmdReset   := %MW300.5;
    bCmdJogCw   := %MW300.6;
    bCmdJogCcw  := %MW300.7;

    (* 제어 부가 비트 (MW301) *)
    bMoveRel    := %MW301.1;

    (* 2. 파라미터 읽기 *)
    (* MW310~313: 위치/속도 (DINT = 2 WORD) *)
    dinTargetPos := WORD_TO_DINT(%MW310) + WORD_TO_DINT(%MW311) * 65536;
    dinTargetVel := WORD_TO_DINT(%MW312) + WORD_TO_DINT(%MW313) * 65536;
    (* MW301.2: JOG 고속/저속 선택 *)
    bJogHigh := %MW301.2;

    (* 3. 수동 엣지 검출 *)
    bEdgeHome   := bCmdHome   AND NOT bPrevHome;
    bEdgeMove   := bCmdMove   AND NOT bPrevMove;
    bEdgeStop   := bCmdStop   AND NOT bPrevStop;
    bEdgeReset  := bCmdReset  AND NOT bPrevReset;

    bPrevHome   := bCmdHome;
    bPrevMove   := bCmdMove;
    bPrevStop   := bCmdStop;
    bPrevReset  := bCmdReset;

    (* 4. 원점복귀 — APM_ORG *)
    IF bEdgeHome THEN
        bOrgReq := TRUE;
        bOrgTimeout := FALSE;
    END_IF;

    g_FB_Org(REQ := bOrgReq, BASE := 0, SLOT := 9, AXIS := 0,
             DONE => bOrgDone, STAT => wOrgStat);

    tonOrgTimeout(IN := bOrgReq, PT := T#30s);
    IF tonOrgTimeout.Q THEN
        bOrgReq := FALSE;
        bOrgTimeout := TRUE;
    END_IF;

    IF bOrgDone OR (wOrgStat <> 0) THEN
        bOrgReq := FALSE;
    END_IF;

    (* 5. 위치 이동 — APM_DST *)
    IF bEdgeMove THEN
        bDstReq := TRUE;
        bDstTimeout := FALSE;
    END_IF;

    g_FB_Dst(REQ := bDstReq, BASE := 0, SLOT := 9, AXIS := 0,
             ADDR := dinTargetPos, SPEED := DINT_TO_UDINT(dinTargetVel),
             DWELL := 0, MCODE := 0,
             POS_SPD := FALSE, ABS_INC := bMoveRel,
             TIME_SEL := 0,
             DONE => bDstDone, STAT => wDstStat);

    tonDstTimeout(IN := bDstReq, PT := T#30s);
    IF tonDstTimeout.Q THEN
        bDstReq := FALSE;
        bDstTimeout := TRUE;
    END_IF;

    IF bDstDone OR (wDstStat <> 0) THEN
        bDstReq := FALSE;
    END_IF;

    (* 6. JOG — APM_JOG (비트 ON 동안 연속 회전) *)
    (* CW 또는 CCW 비트가 ON이면 JOG 실행, 둘 다 OFF면 정지 *)
    IF bCmdJogCw OR bCmdJogCcw THEN
        bJogReq := TRUE;
        IF bCmdJogCw THEN
            bJogDir := TRUE;    (* 1 = 정방향 CW *)
        ELSE
            bJogDir := FALSE;   (* 0 = 역방향 CCW *)
        END_IF;
    ELSE
        bJogReq := FALSE;
    END_IF;

    g_FB_Jog(REQ := bJogReq, BASE := 0, SLOT := 9, AXIS := 0,
             JOG_DIR := bJogDir, LOW_HIGH := bJogHigh,
             DONE => bJogDone, STAT => wJogStat);

    (* 7. 정지 — APM_STP *)
    IF bEdgeStop THEN
        bStpReq := TRUE;
        bJogReq := FALSE;
    END_IF;

    g_FB_Stp(REQ := bStpReq, BASE := 0, SLOT := 9, AXIS := 0,
             DEC_TIME := 0, DONE => bStpDone, STAT => wStpStat);

    IF bStpDone OR (wStpStat <> 0) THEN
        bStpReq := FALSE;
    END_IF;

    (* 8. 에러 리셋 — APM_RST 직접 호출 *)
    IF bEdgeReset THEN
        bRstReq := TRUE;
        wOrgStat := 0;
        wDstStat := 0;
        wStpStat := 0;
        wJogStat := 0;
        bOrgTimeout := FALSE;
        bDstTimeout := FALSE;
        bOrgReq := FALSE;
        bDstReq := FALSE;
        bStpReq := FALSE;
        bJogReq := FALSE;
    END_IF;

    g_FB_Rst(REQ := bRstReq, BASE := 0, SLOT := 9, AXIS := 0,
             INH_OFF := TRUE, DONE => bRstDone, STAT => wRstStat);

    IF bRstDone OR (wRstStat <> 0) THEN
        bRstReq := FALSE;
    END_IF;

    IF bRstDone THEN
        wOrgStat := 0;
        wDstStat := 0;
        wStpStat := 0;
        wJogStat := 0;
        bOrgTimeout := FALSE;
        bDstTimeout := FALSE;
    END_IF;

    (* 9. 서보 상태 비트 -> MW400 *)
    wStatus := 0;
    wRdyStat := %UW0.9.0;

    (* bit0: 동작 중 (원점/이동/JOG) *)
    IF bOrgReq OR bDstReq OR bJogReq THEN
        wStatus := wStatus OR 16#0001;
    END_IF;
    (* bit1: 에러 발생 *)
    IF (wOrgStat <> 0) OR (wDstStat <> 0) OR (wStpStat <> 0) OR (wJogStat <> 0) THEN
        wStatus := wStatus OR 16#0002;
    END_IF;
    (* bit2: 타임아웃 에러 *)
    IF bOrgTimeout OR bDstTimeout THEN
        wStatus := wStatus OR 16#0004;
    END_IF;
    (* bit3: JOG 동작 중 *)
    IF bJogReq THEN
        wStatus := wStatus OR 16#0008;
    END_IF;
    (* bit4: 위치결정모듈 RDY (비트15) *)
    IF (wRdyStat AND 16#8000) <> 16#0000 THEN
        wStatus := wStatus OR 16#0010;
    END_IF;
    (* bit6: 서보MC 출력 상태 *)
    IF %QX0.0.5 THEN
        wStatus := wStatus OR 16#0040;
    END_IF;

    %MW400 := wStatus;

    (* 10. 명령 응답 비트 -> MW401 *)
    wResponse := 0;

    IF bOrgDone THEN
        wResponse := wResponse OR 16#0001;
    END_IF;
    IF bDstDone THEN
        wResponse := wResponse OR 16#0002;
    END_IF;
    IF wOrgStat <> 0 THEN
        wResponse := wResponse OR 16#0004;
    END_IF;
    IF wDstStat <> 0 THEN
        wResponse := wResponse OR 16#0008;
    END_IF;
    IF bRstDone THEN
        wResponse := wResponse OR 16#0010;
    END_IF;
    IF bOrgTimeout THEN
        wResponse := wResponse OR 16#0020;
    END_IF;
    IF bDstTimeout THEN
        wResponse := wResponse OR 16#0040;
    END_IF;

    %MW401 := wResponse;

    (* 11. 위치/속도/에러 -> MW410~415 *)
    %MW410 := %UW0.9.2;
    %MW411 := %UW0.9.3;
    %MW412 := %UW0.9.4;
    %MW413 := %UW0.9.5;

    IF wOrgStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wOrgStat);
    ELSIF wDstStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wDstStat);
    ELSIF wJogStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wJogStat);
    ELSIF wStpStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wStpStat);
    ELSIF wRstStat <> 0 THEN
        %MW414 := UINT_TO_WORD(wRstStat);
    ELSE
        %MW414 := 0;
    END_IF;

    wErrSource := 0;
    IF wOrgStat <> 0 THEN
        wErrSource := wErrSource OR 16#0001;
    END_IF;
    IF wDstStat <> 0 THEN
        wErrSource := wErrSource OR 16#0002;
    END_IF;
    IF wStpStat <> 0 THEN
        wErrSource := wErrSource OR 16#0004;
    END_IF;
    IF wRstStat <> 0 THEN
        wErrSource := wErrSource OR 16#0008;
    END_IF;
    IF bOrgTimeout THEN
        wErrSource := wErrSource OR 16#0010;
    END_IF;
    IF bDstTimeout THEN
        wErrSource := wErrSource OR 16#0020;
    END_IF;
    IF wJogStat <> 0 THEN
        wErrSource := wErrSource OR 16#0040;
    END_IF;
    %MW415 := wErrSource;

END_IF;

